{"content":"package kotlinx.datetime.test

import kotlinx.datetime.*
import kotlin.test.*

class ReproductionTest {
    @Test
    fun testLocalDateParseLeadingZeros() {
        val input = "+00000000000002022-07-16"
        val result = LocalDate.parse(input)
        assertEquals(LocalDate(2022, 7, 16), result)
    }

    @Test
    fun testLocalDateTimeParseLeadingZeros() {
        val input = "+00000000000002022-07-16T10:00:00"
        val result = LocalDateTime.parse(input)
        assertEquals(LocalDateTime(2022, 7, 16, 10, 0, 0), result)
    }

    @Test
    fun testDateTimePeriodParseEmptyP() {
        assertFailsWith<IllegalArgumentException> {
            DateTimePeriod.parse("P")
        }
    }

    @Test
    fun testDatePeriodParseEmptyP() {
        assertFailsWith<IllegalArgumentException> {
            DatePeriod.parse("P")
        }
    }
}
","file_path":"core/jvm/test/ReproductionTest.kt"}

